// Принимает ответ /call-center/api/orders__deprecated.
// Возвращает один item: { orders: [...], count, fetched_at }.
//
// Замечание: API может вернуть {status:'error', message:'Заказы отсутствуют', data:[]}
// при пустом активном списке — это НЕ ошибка, обрабатываем как пустой массив.

const input = $input.first()?.json ?? {};

let payload = input;
if (typeof input === 'string') {
  try { payload = JSON.parse(input); } catch (e) {
    throw new Error('Listing body is not JSON: ' + String(input).slice(0, 200));
  }
}
if (typeof payload?.data === 'string') {
  try { payload = JSON.parse(payload.data); } catch (e) {
    throw new Error('Listing.data is not JSON: ' + String(payload.data).slice(0, 200));
  }
}

const rows = Array.isArray(payload?.data) ? payload.data : null;
if (rows === null) {
  throw new Error('Listing response has no data array. Got keys: ' + Object.keys(payload || {}).join(','));
}

const orders = rows.map(r => ({
  order_id: Number(r.id),
  client_phone: typeof r.ClientPhone === 'string' ? r.ClientPhone.replace(/[^0-9]/g, '') : null,
  order_type: typeof r.order_type === 'number' ? r.order_type : null,
  status_raw: r.Status,
  raw: r
})).filter(o => Number.isFinite(o.order_id));

return [{ json: { orders, count: orders.length, fetched_at: new Date().toISOString() } }];

// Дифф между текущим листингом и снимком из БД.
// Читает оба источника через cross-references — нода работает даже при
// пустом входе (например, БД пустая → Load Known даёт 0 items).

const listing = ($('Validate Listing').first()?.json?.orders) || [];
const known   = $('Load Known').all().map(i => i.json).filter(j => j && j.order_id != null);

const byIdListing = new Map(listing.map(o => [o.order_id, o]));
const byIdKnown   = new Map(known.map(k => [Number(k.order_id), k]));

const events = [];

for (const o of listing) {
  const k = byIdKnown.get(o.order_id);
  if (!k) {
    events.push({
      event_type: 'new_order',
      order_id: o.order_id,
      client_phone: o.client_phone,
      order_type: o.order_type,
      status_raw: o.status_raw,
      raw: o.raw,
      detected_at: new Date().toISOString()
    });
    continue;
  }
  if (String(o.status_raw) !== String(k.last_status)) {
    events.push({
      event_type: 'status_changed',
      order_id: o.order_id,
      client_phone: o.client_phone || k.client_phone,
      order_type: o.order_type ?? k.order_type,
      from_status: k.last_status,
      to_status: o.status_raw,
      raw: o.raw,
      detected_at: new Date().toISOString()
    });
  }
}

for (const k of known) {
  if (!byIdListing.has(Number(k.order_id))) {
    events.push({
      event_type: 'order_closed',
      order_id: Number(k.order_id),
      client_phone: k.client_phone,
      order_type: k.order_type,
      last_known_status: k.last_status,
      detected_at: new Date().toISOString()
    });
  }
}

if (events.length === 0) {
  return [{ json: { _no_events: true, listing_count: listing.length, known_count: known.length, fetched_at: new Date().toISOString() } }];
}

return events.map(e => ({ json: e }));
